<span class="line"><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">Response: </span><span style="--shiki-light:#CD3131;--shiki-dark:#F44747;">\`</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&lt;</span><span style="--shiki-light:#CD3131;--shiki-dark:#F44747;">think</span><span style="--shiki-light:#000000;--shiki-dark:#D4D4D4;">&gt;</span><span style="--shiki-light:#CD3131;--shiki-dark:#F44747;">\`</span></span>
